#!/usr/bin/env bash
# This file was generated by Cursor AI on 2026-05-12.

set -euo pipefail

usage() {
  cat <<'EOF'
Usage: get_benchmarks.sh BENCHMARKS_DIR

Walk BENCHMARKS_DIR for *.mltl and *.c2po files and write matching paths (sorted)
to BENCHMARKS_DIR/benchmarks.txt.

Patterns (first match wins):
  */boeing-wbs/*.c2po
  */nasa-atc/*.c2po
  */mtl-patterns/*.mltl
  *.mltl
EOF
}

if [[ $# -ne 1 ]]; then
  usage >&2
  exit 1
fi

BENCHMARK_ROOT="$(cd "$1" && pwd)"
OUT_FILE="${BENCHMARK_ROOT}/benchmarks.txt"

if [[ ! -d "$BENCHMARK_ROOT" ]]; then
  echo "Not a directory: $1" >&2
  exit 1
fi

: >"$OUT_FILE"

while IFS= read -r file; do
  case "${file}" in
    */boeing-wbs/*.c2po) echo "${file}" >>"$OUT_FILE" ;;
    */nasa-atc/*.c2po) echo "${file}" >>"$OUT_FILE" ;;
    */mtl-patterns/*.mltl) echo "${file}" >>"$OUT_FILE" ;;
    *.mltl) echo "${file}" >>"$OUT_FILE" ;;
  esac
done < <(find "$BENCHMARK_ROOT" -type f \( -name '*.mltl' -o -name '*.c2po' \) | sort)

echo "Wrote ${OUT_FILE}"
